#![expect(
    clippy::expect_used,
    clippy::unwrap_used,
    reason = "integration tests use expect/unwrap for assertion clarity"
)]
//! Behavioural tests: `cf_status` returns a typed `StatusSummary`.
//!
//! Slice: state_view — cf_status structured output.

use cfk_core::types::ids::WorkItemId;
use cfk_core::types::phase::PhaseKind;
use cfk_core::types::routing::WorkType;
use cfk_engine::events::{FactoryEvent, append_event};
use cfk_engine::forge::MemoryForge;
use cfk_mcp::server::{BacklogAddParams, CfkServer, InitParams, PhaseFilterParams};
use rmcp::handler::server::wrapper::Parameters;
use rmcp::model::{CallToolResult, RawContent};
use serde::Deserialize;
use tempfile::TempDir;

#[derive(Debug, Deserialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PhaseStatusCounts {
    pub phase: String,
    pub ready: usize,
    pub in_progress: usize,
    pub done: usize,
    pub abandoned: usize,
}

#[derive(Debug, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct StatusSummary {
    pub project_id: String,
    pub phases: Vec<PhaseStatusCounts>,
}

fn make_server(dir: &TempDir) -> CfkServer {
    CfkServer::load_with_forge(dir.path().to_path_buf(), MemoryForge::new())
        .expect("server load should succeed on empty directory")
}

fn is_error(result: &CallToolResult) -> bool {
    result.is_error.unwrap_or(false)
}

fn result_text(result: &CallToolResult) -> String {
    result
        .content
        .iter()
        .filter_map(|c| {
            if let RawContent::Text(t) = &c.raw {
                Some(t.text.as_str())
            } else {
                None
            }
        })
        .collect::<Vec<_>>()
        .join("")
}

async fn init_project(server: &CfkServer, dir: &TempDir) {
    let result = server
        .cf_init(Parameters(InitParams {
            project_root: Some(dir.path().to_str().unwrap().to_string()),
        }))
        .await
        .expect("cf_init should not return McpError");
    assert!(!is_error(&result), "cf_init failed: {}", result_text(&result));
}

async fn add_work_item(server: &CfkServer, phase: PhaseKind, work_type: WorkType, description: &str) -> String {
    let result = server
        .cf_backlog_add(Parameters(BacklogAddParams {
            phase,
            work_type,
            description: description.to_string(),
        }))
        .await
        .expect("cf_backlog_add should not return McpError");
    assert!(!is_error(&result), "cf_backlog_add failed: {}", result_text(&result));
    let raw = result_text(&result);
    let v: serde_json::Value =
        serde_json::from_str(&raw).expect("backlog_add response is valid JSON");
    v["work_item_id"].as_str().expect("work_item_id present").to_string()
}

async fn raw_cf_status(server: &CfkServer) -> String {
    let result = server
        .cf_status(Parameters(PhaseFilterParams { phase: None }))
        .await
        .expect("cf_status should not return McpError");
    assert!(!is_error(&result), "cf_status returned a tool error: {}", result_text(&result));
    result_text(&result)
}

// Fails under production: serde rejects unknown `blocked` field due to deny_unknown_fields.
async fn call_cf_status(server: &CfkServer) -> StatusSummary {
    let raw = raw_cf_status(server).await;
    serde_json::from_str(&raw).unwrap_or_else(|e| {
        panic!("cf_status response did not deserialise into StatusSummary: {e}\nRaw: {raw}")
    })
}

fn abandon_work_item(dir: &TempDir, work_item_id: WorkItemId) {
    let event_dir = cfk_engine::store::event_export_dir(dir.path());
    let abandon_seq: u64 = std::fs::read_dir(&event_dir)
        .expect("event dir must exist")
        .filter_map(std::result::Result::ok)
        .count() as u64
        + 1;
    append_event(
        dir.path(),
        abandon_seq,
        FactoryEvent::WorkItemAbandoned { work_item_id },
    )
    .expect("append_event must succeed");
}

// Scenario 1: every phase entry JSON contains the key "abandoned".
// Expected failure: obj.contains_key("abandoned") is false; production emits `blocked`.
#[tokio::test]
async fn cf_status_phase_entry_has_abandoned_field() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;
    add_work_item(&server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "Some slice").await;

    let raw = raw_cf_status(&server).await;
    let v: serde_json::Value = serde_json::from_str(&raw).expect("valid JSON");
    let phases = v["phases"].as_array().expect("phases array");
    for entry in phases {
        let obj = entry.as_object().expect("phase entry is object");
        assert!(
            obj.contains_key("abandoned"),
            "phase entry must contain 'abandoned'; got: {:?}",
            obj.keys().collect::<Vec<_>>()
        );
    }
}

// Scenario 2: no phase entry JSON contains the legacy key "blocked".
// Expected failure: obj.contains_key("blocked") is true; production emits `blocked`.
#[tokio::test]
async fn cf_status_phase_entry_has_no_blocked_field() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;
    add_work_item(&server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "Some slice").await;

    let raw = raw_cf_status(&server).await;
    let v: serde_json::Value = serde_json::from_str(&raw).expect("valid JSON");
    let phases = v["phases"].as_array().expect("phases array");
    for entry in phases {
        let obj = entry.as_object().expect("phase entry is object");
        assert!(
            !obj.contains_key("blocked"),
            "phase entry must NOT contain 'blocked'; got: {:?}",
            obj.keys().collect::<Vec<_>>()
        );
    }
}

// Scenario 3: full response deserialises into StatusSummary (deny_unknown_fields).
// Expected failure: serde panics with "unknown field `blocked`" before the assertion.
#[tokio::test]
async fn cf_status_response_round_trips_into_status_summary() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;
    add_work_item(&server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "Some slice").await;

    let summary: StatusSummary = call_cf_status(&server).await;
    assert!(!summary.phases.is_empty(), "StatusSummary.phases must not be empty after adding a work item");
}

// Scenario 4: development phase reports ready=2 after adding 2 ready work items.
// Expected failure: call_cf_status panics (serde rejects unknown `blocked`) before ready=2 assertion.
#[tokio::test]
async fn cf_status_development_phase_shows_ready_count() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;
    for desc in ["Implement login slice", "Implement logout slice"] {
        add_work_item(&server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, desc).await;
    }

    let summary = call_cf_status(&server).await;
    let dev = summary.phases.iter().find(|p| p.phase == "development")
        .unwrap_or_else(|| panic!("no development entry; got: {:?}", summary.phases.iter().map(|p| &p.phase).collect::<Vec<_>>()));
    assert_eq!(dev.ready, 2, "development phase must report ready=2");
}

// Scenario 5: abandoned items are counted as abandoned=1.
// Expected failure: call_cf_status panics (serde rejects unknown `blocked`) before abandoned=1 assertion.
#[tokio::test]
async fn cf_status_abandoned_items_counted_separately_from_done() {
    let dir = TempDir::new().expect("tempdir");
    let setup_server = make_server(&dir);
    init_project(&setup_server, &dir).await;
    add_work_item(&setup_server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "Stays ready").await;
    let id_str = add_work_item(&setup_server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "To abandon").await;
    let wid = WorkItemId::try_new(uuid::Uuid::parse_str(&id_str).expect("valid uuid")).expect("valid WorkItemId");
    abandon_work_item(&dir, wid);

    let observe_server = make_server(&dir);
    let summary = call_cf_status(&observe_server).await;
    let dev = summary.phases.iter().find(|p| p.phase == "development")
        .unwrap_or_else(|| panic!("no development entry"));
    assert_eq!(dev.abandoned, 1, "abandoned item must appear as abandoned=1");
}

// Scenario 6: abandoned items are NOT counted as done.
// Expected failure: call_cf_status panics (serde rejects unknown `blocked`) before done=0 assertion.
#[tokio::test]
async fn cf_status_abandoned_items_not_counted_as_done() {
    let dir = TempDir::new().expect("tempdir");
    let setup_server = make_server(&dir);
    init_project(&setup_server, &dir).await;
    add_work_item(&setup_server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "Stays ready").await;
    let id_str = add_work_item(&setup_server, PhaseKind::Development, WorkType::OuterBehavioralTestWriting, "To abandon").await;
    let wid = WorkItemId::try_new(uuid::Uuid::parse_str(&id_str).expect("valid uuid")).expect("valid WorkItemId");
    abandon_work_item(&dir, wid);

    let observe_server = make_server(&dir);
    let summary = call_cf_status(&observe_server).await;
    let dev = summary.phases.iter().find(|p| p.phase == "development")
        .unwrap_or_else(|| panic!("no development entry"));
    assert_eq!(dev.done, 0, "abandoned items must not be counted as done");
}
